mapper.select:
SELECT booking_number, date, booking_to, customer_name, origin, destination, booking_status, booking_class
FROM booking
WHERE booking_number = #{bookingNumber}
  AND customer_name = #{customerName}

mapper.update:
UPDATE booking
SET date        = #{newDate},
    origin      = #{origin},
    destination = #{destination}
WHERE booking_number = #{bookingNumber}
  AND customer_name = #{customerName}

UPDATE booking
SET booking_status = #{status}
WHERE booking_number = #{bookingNumber}
  AND customer_name = #{customerName}
